    }

    if (pos >= end) {
        if (shouldEmitInvalidEscapeError) {
            error(Diagnostics.Unexpected_end_of_text);
        }
        isInvalidExtendedEscape = true;
    }
    else if (charCodeUnchecked(pos) === CharacterCodes.closeBrace) {
