function peekUnicodeEscape(): number {
    if (pos + 5 < end && charCodeUnchecked(pos + 1) === CharacterCodes.u) {
        const start = pos;
        pos += 2;
        const value = scanExactNumberOfHexDigits(4, /*canHaveSeparators*/ false);
